"use strict";(self.webpackChunkwebsite=self.webpackChunkwebsite||[]).push([[435],{3601:e=>{e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"someSidebar":[{"type":"category","label":"Introduction","items":[{"type":"link","href":"/dotnet-activemq-artemis-client/docs/getting-started","label":"Getting Started","docId":"getting-started","unlisted":false},{"type":"link","href":"/dotnet-activemq-artemis-client/docs/dependency-injection","label":"Dependency Injection","docId":"dependency-injection","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Features","items":[{"type":"link","href":"/dotnet-activemq-artemis-client/docs/message-payload","label":"Message Payload","docId":"message-payload","unlisted":false},{"type":"link","href":"/dotnet-activemq-artemis-client/docs/message-durability","label":"Message Durability","docId":"message-durability","unlisted":false},{"type":"link","href":"/dotnet-activemq-artemis-client/docs/message-priority","label":"Message Priority","docId":"message-priority","unlisted":false},{"type":"link","href":"/dotnet-activemq-artemis-client/docs/message-acknowledgment","label":"Message Acknowledgment","docId":"message-acknowledgment","unlisted":false},{"type":"link","href":"/dotnet-activemq-artemis-client/docs/consumer-credit","label":"Consumer Credit","docId":"consumer-credit","unlisted":false},{"type":"link","href":"/dotnet-activemq-artemis-client/docs/message-filtering","label":"Message Filtering","docId":"message-filtering","unlisted":false},{"type":"link","href":"/dotnet-activemq-artemis-client/docs/connection-lifecycle","label":"Connection Lifecycle","docId":"connection-lifecycle","unlisted":false},{"type":"link","href":"/dotnet-activemq-artemis-client/docs/auto-recovery","label":"Automatic Recovery","docId":"auto-recovery","unlisted":false},{"type":"link","href":"/dotnet-activemq-artemis-client/docs/transactions","label":"Transactions","docId":"transactions","unlisted":false},{"type":"link","href":"/dotnet-activemq-artemis-client/docs/messaging-model","label":"Messaging Model","docId":"messaging-model","unlisted":false},{"type":"link","href":"/dotnet-activemq-artemis-client/docs/request-reply","label":"Request Reply","docId":"request-reply","unlisted":false},{"type":"link","href":"/dotnet-activemq-artemis-client/docs/testing","label":"Testing","docId":"testing","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Community","items":[{"type":"link","href":"/dotnet-activemq-artemis-client/docs/online-resources","label":"Online resources","docId":"online-resources","unlisted":false}],"collapsed":true,"collapsible":true}]},"docs":{"auto-recovery":{"id":"auto-recovery","title":"Automatic Recovery From Network Failures","description":"A network connection between clients and Artemis nodes can fail. The client library supports the automatic recovery of connections, producers, and consumers. Automatic recovery is enabled by default.","sidebar":"someSidebar"},"connection-lifecycle":{"id":"connection-lifecycle","title":"Connection Lifecycle","description":"Once the connection to the broker has been established, the IConnection interface can notify you about several important events that may occur throughout the connection lifecycle.","sidebar":"someSidebar"},"consumer-credit":{"id":"consumer-credit","title":"Consumer Credit","description":"A consumer can control the flow of messages from a broker by allocating credit for a particular number of messages. As the broker delivers messages, it spends this credit. Each delivered message results in decrementing the available message credit by one. Each message acknowledged by the client increments the available message credit by one.","sidebar":"someSidebar"},"dependency-injection":{"id":"dependency-injection","title":"Dependency Injection","description":"ArtemisNetClient.Extensions.DependencyInjection integrates ArtemisNetClient with Microsoft.Extensions.DependencyInjection. For ASP.NET Core applications, it is the easiest way to register long-lived connections, consumers, producers, and request-reply clients.","sidebar":"someSidebar"},"getting-started":{"id":"getting-started","title":"Getting started","description":".NET Client for Apache Artemis is a lightweight library built on top of AmqpNetLite. The main goal of this project is to provide a simple API that fully leverages Apache Artemis capabilities in .NET.","sidebar":"someSidebar"},"message-acknowledgment":{"id":"message-acknowledgment","title":"Message Acknowledgment","description":"After receiving a message, the consumer must signal the broker with the outcome of message processing. The client supports four acknowledgment modes: Accept, Reject, Modify, and handling of unacknowledged messages on consumer close. Unsettled deliveries are eligible for redelivery when the consumer is closed or disposed (exact behavior depends on whether the consumer is durable or non-durable).","sidebar":"someSidebar"},"message-durability":{"id":"message-durability","title":"Message Durability Modes","description":"Artemis supports two types of durability modes for messages: durable and nondurable. By default each message sent by the client using SendAsync method is durable. That means that the broker actually has to persist the message on the disk before the confirmation frame (ack) will be sent back to the client. The confirmation frame is what we can await for.","sidebar":"someSidebar"},"message-filtering":{"id":"message-filtering","title":"Message Filtering","description":"Message filtering allows consumers to selectively receive messages based on specific criteria. The .NET client supports two types of filtering: filter expressions and the NoLocal filter.","sidebar":"someSidebar"},"message-payload":{"id":"message-payload","title":"Message Payload","description":"The client uses Message class to represent messages which may be transmitted. A Message can carry various types of payload and accompanying metadata.","sidebar":"someSidebar"},"message-priority":{"id":"message-priority","title":"Message Priority","description":"This property defines the level of importance of a message. Artemis uses it to prioritize message delivery. Messages with higher priority will be delivered before messages with lower priority. Messages with the same priority level should be delivered according to the order they were sent with. There are 10 levels of message priority, ranging from 0 (the lowest) to 9 (the highest). If no message priority is set on the client (Priority set to null), the message will be treated as if it was assigned a normal priority (4).","sidebar":"someSidebar"},"messaging-model":{"id":"messaging-model","title":"Messaging Model","description":"Apache Artemis messaging model is built on top of three main concepts: addresses, queues and routing types.","sidebar":"someSidebar"},"online-resources":{"id":"online-resources","title":"Online resources","description":"Blog posts","sidebar":"someSidebar"},"request-reply":{"id":"request-reply","title":"Request Reply","description":"Request-reply is one of the basic messaging patterns. From a high level, a request-reply scenario involves an application that sends a message (the request) and expects to receive a message in return (the reply).","sidebar":"someSidebar"},"testing":{"id":"testing","title":"Testing","description":"Automated testing is a crucial and intrinsic part of the software development cycle. .NET Client for Apache Artemis comes with a dedicated package ArtemisNetClient.Testing that will help you to test the messaging-dependent part of your application with ease in a controlled but realistic environment.","sidebar":"someSidebar"},"transactions":{"id":"transactions","title":"Transactions","description":"Artemis provides several guarantees regarding reliable message delivery and processing. In Message Durability Modes section, you may learn how to send a single message so it won\'t be lost in transit.","sidebar":"someSidebar"}}}}')}}]);